import React from "react"
import unicode, { getChart } from "./unicode"

const idx = [
  "Name",
  "Category",
  "Class",
  "Bi-direction",
  "Mapping",
  "Decimal Digit Value",
  "Digit Value",
  "Numeric Value",
  "Mirrored",
  "Unicode Name",
  "Comment",
  "Uppercase Mapping",
  "Lowercase Mapping",
  "Titlecase Mapping",
]

const Inspector = ({ code, handleDelete = null, ...props }) => {
  const exist = Boolean(unicode[code])
  return (
    <div className={`inspector ${exist ? " ok" : ""}`}>
      <h2>Inspector</h2>
      {handleDelete && (
        <button title="Dismiss" className="delete-btn" onClick={handleDelete}>
          ✖
        </button>
      )}
      <span className="symbol center">{String.fromCodePoint(code)}</span>
      <div className="chartset">{getChart(code)}</div>

      <dl {...props}>
        {exist ? (
          unicode[code].map((li, i) => {
            if (li !== "") {
              return (
                <React.Fragment key={`sym-${code}-${i}`}>
                  <dt>{idx[i]}</dt>
                  <dd>{li}</dd>
                </React.Fragment>
              )
            } else return null
          })
        ) : (
          <sub>This character is not in current dataset.</sub>
        )}
      </dl>
    </div>
  )
}

export default Inspector
