import React, { useRef, useState } from "react"

import { Helmet } from "react-helmet"
import symbolsCss from "!raw-loader!sass-loader!../css/symbol.scss"
import SEO from "../components/seo.js"
import data from "../datasheet/symbols.yml"

import { toArray, map, kebabCase, concat } from "lodash"

import { getName } from "../components/symbols/unicode"
import LogoSvg from "../components/symbols/logo-svg"
import Side from "../components/symbols/side"
import Extra from "../components/symbols/extraset"
import Header from "../components/symbols/header"
import Spy from "../components/symbols/scrollSpy"

// console.log(logoSvg)
const CopyToClipboard = div => {
  var range = null
  if (document.selection) {
    range = document.body.createTextRange()
    range.moveToElementText(div)
    range.select().createTextRange()
    document.execCommand("copy")
  } else if (window.getSelection) {
    window.getSelection().removeAllRanges()
    range = document.createRange()
    range.selectNode(div)
    range.setEnd(div, 1) // Prevent Newline
    window.getSelection().addRange(range)
    document.execCommand("copy")
    window.getSelection().removeAllRanges()
  }
}

const SymbolCard = ({
  sym = "?",
  title = "Symbol",
  desc = [],
  setSymCode = null,
}) => {
  const ref = useRef(null)
  // Sanitize Symbols
  sym = toArray(sym)[0]
  var htmlCode = -1
  try {
    htmlCode = encodeURIComponent(sym)
  } catch (URIError) {
    htmlCode = "Not legal"
  }
  const codePoint = sym.codePointAt(0)
  const hexCode = codePoint.toString(16).toUpperCase()
  const clickToClip = () => {
    CopyToClipboard(ref?.current)
  }
  const handleFocus = e => {
    if (setSymCode) {
      setSymCode(codePoint)
    }
  }
  return (
    <div className="word-card">
      <div
        className="symbol btn"
        tabIndex="0"
        data-sym={sym}
        ref={ref}
        role="button"
        aria-pressed="false"
        aria-label="Copy Symbol"
        onClick={clickToClip}
        onKeyPress={clickToClip}
        onFocus={handleFocus}
        // onBlur={handleBlur}
        children={sym}
      />
      <div className="desc">
        <span className="char-tag">
          {codePoint}(0x{hexCode})
        </span>
        <span className="desc-title">{title}</span>
        <span className="desc-keys">{desc.join(", ")}</span>
        <span className="html-tag">{htmlCode}</span>
      </div>
    </div>
  )
}

const get_genre_id = genre => `genre-${kebabCase(genre)}`
const genre_list = concat(
  map(data.symbols, (symbols, genre) => genre),
  map(Extra, (arr, genre) => genre)
)

const SideArea = ({ symCode, delete_sym, ...props }) => {
  const [open, setOpen] = useState(false)
  const handleBtn = e => {
    setOpen(!open)
  }
  const id_target = map(genre_list, genre => get_genre_id(genre))
  return (
    <div className={`side${open ? " open" : ""}`}>
      <button className="side-handler" onClick={handleBtn}>
        ☰
      </button>
      <div className="side-container">
        <h2>Index</h2>
        <Spy target={id_target} />
        <Side code={symCode} handleDelete={delete_sym} />
      </div>
    </div>
  )
}

const Symbol = () => {
  const [symCode, setSymCode] = useState(null)
  const delete_sym = e => {
    setSymCode(null)
  }

  return (
    <>
      <SEO {...data.SEO}></SEO>
      <Helmet>
        <style>{symbolsCss}</style>
      </Helmet>
      <div className="grid-system">
        <div className="nav">
          <LogoSvg className="svg-logo" />
        </div>
        <div className="main">
          <Header />
          {map(data.symbols, (symbols, genre) => {
            return (
              <React.Fragment key={`Genre-${genre}`}>
                <h2>{genre}</h2>
                <div className="symbol-list" id={`${get_genre_id(genre)}`}>
                  {map(symbols, (obj, key) => {
                    return (
                      <SymbolCard
                        sym={key}
                        {...obj}
                        key={`sym-${key}`}
                        setSymCode={setSymCode}
                      />
                    )
                  })}
                </div>
              </React.Fragment>
            )
          })}
          {map(Extra, (arr, genre) => {
            return (
              <React.Fragment key={`Genre-${genre}`}>
                <h2>{genre}</h2>
                <div className="symbol-list" id={`${get_genre_id(genre)}`}>
                  {map(arr, key => {
                    return (
                      <SymbolCard
                        sym={key}
                        key={`sym-${key}`}
                        title={getName(key)}
                        setSymCode={setSymCode}
                      />
                    )
                  })}
                </div>
              </React.Fragment>
            )
          })}
        </div>
        <SideArea symCode={symCode} delete_sym={delete_sym} />
      </div>
    </>
  )
}

export default Symbol
