import { range, map, concat, mapValues } from "lodash"
const data = {
  Date: [
    [12992, 13003],
    [13280, 13310],
  ],
  "Control Pictures": [[9216, 9254]],
  "Square Unit Symbols": [
    [13169, 13174],
    [13184, 13277],
  ],
}

const chart = mapValues(data, arr => {
  return map(concat(...map(arr, ([from, to]) => range(from, to + 1))), n =>
    String.fromCodePoint(n)
  )
})

export default chart
