import React, { useEffect, useState } from "react"
import { each, clone, startCase } from "lodash"
const handleSmoothScrollToId = id => e => {
  const element = document.getElementById(id)
  if (element) {
    e.preventDefault()
    element.scrollIntoView({ behavior: "smooth" })
  } else {
    return
  }
}
const Spy = ({ target }) => {
  const [vis, setVis] = useState({})
  const setVisById = id => visible => {
    setVis(last_vis => {
      const newvis = clone(last_vis)
      newvis[id] = visible
      return newvis
    })
  }
  const id_set = Object.assign(
    {},
    ...target.map(id => ({ [id]: setVisById(id) }))
  )
  useVisible(id_set)
  return (
    <ul className="toc">
      {target.map(id => {
        return (
          <li key={id} className={`${vis && (vis[id] ? "vis" : "")}`}>
            <a href={`#${id}`} onClick={handleSmoothScrollToId(id)}>
              {startCase(id)}
            </a>
          </li>
        )
      })}
    </ul>
  )
}

const useVisible = (id_set = {}) => {
  useEffect(() => {
    const handleIntersect = (entries, opts) => {
      entries.forEach(entry => {
        // console.log(entry)
        const visible = entry.isIntersecting
        const callback = id_set[entry.target.id]
        if (callback) {
          callback(visible)
        } else {
          // console.log("No callback")
        }
      })
    }
    const opt = {
      root: null,
      threshold: 0.01,
    }
    const observer = new IntersectionObserver(handleIntersect, opt)

    each(id_set, (callback, target) => {
      const element = document.getElementById(target)
      if (!element) {
        // console.log("Not found")
        return
      }
      observer.observe(element)
      // console.log("Obs")
    })

    // Clean Up
    return () => {
      observer.disconnect()
    }
  }, [id_set])
}

export default Spy
export { useVisible }
